import{_ as t,o,c as a,ag as r}from"./chunks/framework.C9sp7nFj.js";const h=JSON.parse('{"title":"QQ Channel Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"channels/qq.md","filePath":"channels/qq.md","lastUpdated":1778282751000}'),n={name:"channels/qq.md"};function i(l,e,s,c,p,g){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="qq-channel-configuration" tabindex="-1">QQ Channel Configuration <a class="header-anchor" href="#qq-channel-configuration" aria-label="Permalink to &quot;QQ Channel Configuration&quot;">​</a></h1><p>Connecting your Memoh Bot to QQ allows it to interact with users through QQ&#39;s official Bot platform.</p><h2 id="step-1-create-a-qq-bot" tabindex="-1">Step 1: Create a QQ Bot <a class="header-anchor" href="#step-1-create-a-qq-bot" aria-label="Permalink to &quot;Step 1: Create a QQ Bot&quot;">​</a></h2><ol><li>Go to the <a href="https://q.qq.com/qqbot/openclaw/" target="_blank" rel="noreferrer">QQ Bot Open Platform</a> and log in with your QQ account.</li><li>Click <strong>Create Bot</strong> (创建机器人) - no approval required. Each account can create up to 5 bots.</li><li>Copy the <strong>AppID</strong> and <strong>AppSecret</strong> displayed on the page.</li></ol><blockquote><p><strong>Important</strong>: AppSecret is only shown once. Save it securely - viewing it again will force a reset.</p></blockquote><h2 id="step-2-configure-memoh" tabindex="-1">Step 2: Configure Memoh <a class="header-anchor" href="#step-2-configure-memoh" aria-label="Permalink to &quot;Step 2: Configure Memoh&quot;">​</a></h2><ol><li>Go to your Bot&#39;s <strong>Platforms</strong> tab in the Memoh Web UI.</li><li>Click <strong>Add Channel</strong> and select <strong>QQ</strong>.</li><li>Paste your <strong>AppID</strong> and <strong>AppSecret</strong>.</li><li>Configure optional settings: <ul><li><strong>Markdown Support</strong>: Enable Markdown formatting (default: enabled).</li><li><strong>Enable Input Hint</strong>: Show typing indicators (default: enabled).</li></ul></li><li>Click <strong>Save and Enable</strong>.</li></ol><h2 id="features-supported" tabindex="-1">Features Supported <a class="header-anchor" href="#features-supported" aria-label="Permalink to &quot;Features Supported&quot;">​</a></h2><ul><li><strong>Message Content</strong>: Full support for text messages.</li><li><strong>Markdown</strong>: Rich formatting with bold, italic, code blocks, and links.</li><li><strong>Attachments</strong>: Support for images and files.</li><li><strong>Typing Indicators</strong>: Visual feedback while generating responses.</li><li><strong>Target Types</strong>: C2C (direct message), group, and channel.</li></ul><h2 id="official-resources" tabindex="-1">Official Resources <a class="header-anchor" href="#official-resources" aria-label="Permalink to &quot;Official Resources&quot;">​</a></h2><ul><li><a href="https://q.qq.com/" target="_blank" rel="noreferrer">QQ Bot Open Platform</a></li><li><a href="https://bot.q.qq.com/wiki/" target="_blank" rel="noreferrer">QQ Bot Documentation</a></li></ul>',11)])])}const d=t(n,[["render",i]]);export{h as __pageData,d as default};
